  const runId = runIdForSeed(seed);
  const startPosition = unplacedPosition();
  const playerHp = gameConfig.playerCharacter.stats.hp.start;
  const playerFullness = gameConfig.playerCharacter.stats.fullness.start;

  return {
    version: {
      protocolVersion: PROTOCOL_VERSION,
      engineVersion: ENGINE_VERSION,
    },
    run: {
      runId,
      seed,
      depth,
      band,
      turn,
      terminalStatus: ACTIVE_TERMINAL_STATUS,
      itemKnowledge: {
        identifiedDefinitionIds: [],
        bonusRevealedItemInstanceIds: [],
        chargesByItemInstanceId: {},
      },
    },
    floor: {
      floorId: `floor#${depth}`,
      depth,
      band,
      geometry: {
        refId: `floor-geometry#${depth}`,
        opaque: null,
      },
    },
    player: {
      hp: {
        current: playerHp,
        max: playerHp,
      },
      level: gameConfig.playerCharacter.stats.level.start,
      xp: 0,
      fullness: {
        current: playerFullness,
        max: bounds.playerCharacter.fullnessCap,
      },
      position: startPosition,
      inventory: Array.from(
        { length: gameConfig.playerCharacter.inventory.slots },
        () => null,
      ),
      equipment: {
        weapon: null,
        armor: null,
        charms: Array.from(
          { length: gameConfig.playerCharacter.equipmentSlots.charms },
          () => null,
        ),
      },
      statuses: [],
    },
    entities: {},
    quests: {
      quests: {},
      activeQuestIds: [],
      completedQuestIds: [],
      failedQuestIds: [],
    },
    log: [
      {
        turn,
        type: "state_created",
        data: {
          runId,
          seed,
          depth,
          band,
        },
      },
    ],
    rng: {
      rootSeed: seed,
      streams: {
        [ROOT_RNG_STREAM_ID]: {
          streamId: ROOT_RNG_STREAM_ID,
          seed,
          parentStreamId: null,
          draws: 0,
        },
      },
    },
    ids: {
      entityCounters: createInitialEntityCounters(),
    },
  };
};

const runIdForSeed = (seed: string): string => `run#${seed}`;

const unplacedPosition = (): Position => ({
  x: 0,
  y: 0,
});

const initialDepth = (gameConfig: GameConfig): number => {
  const entries = depthBandEntries(gameConfig);
  const firstEntry = entries[0];

  if (firstEntry === undefined) {
    throw new RangeError("config must define at least one depth band");
  }

  let depth = firstEntry[1].minFloor;
  for (const [, range] of entries) {
    if (range.minFloor < depth) {
      depth = range.minFloor;
    }
  }

  return depth;
};

const depthBandEntries = (
  gameConfig: GameConfig,
): readonly [
  DepthBand,
  {
    readonly minFloor: number;
    readonly maxFloor: number;
  },
][] =>
  Object.entries(gameConfig.runStructure.depthBands) as readonly [
    DepthBand,
    {
      readonly minFloor: number;
      readonly maxFloor: number;
    },
  ][];

import { formatLogEvent } from "@engine/render";
import type { GameState } from "@engine/state";

export type LogLineView = {
  readonly index: number;
  readonly turn: number;
  readonly text: string;
  readonly key: string;
};

export type LogGroupView = {
  readonly turn: number;
  readonly lines: readonly LogLineView[];
};

export type MessageLogViewModel = {
  readonly windowSize: number;
  readonly windowLines: readonly LogLineView[];
  readonly windowGroups: readonly LogGroupView[];
  readonly historyLines: readonly LogLineView[];
  readonly historyGroups: readonly LogGroupView[];
  readonly hiddenLineCount: number;
};

export const DEFAULT_LOG_WINDOW_SIZE = 6;

export const createMessageLogViewModel = (
  state: GameState,
  windowSize = DEFAULT_LOG_WINDOW_SIZE,
): MessageLogViewModel => {
  const historyLines = formattedLines(state);
  const clampedWindowSize = Math.max(1, Math.floor(windowSize));
  const windowLines = historyLines.slice(-clampedWindowSize);

  return {
    windowSize: clampedWindowSize,
    windowLines,
    windowGroups: groupConsecutiveTurns(windowLines),
    historyLines,
    historyGroups: groupConsecutiveTurns(historyLines),
    hiddenLineCount: Math.max(0, historyLines.length - windowLines.length),
  };
};

const formattedLines = (state: GameState): readonly LogLineView[] =>
  state.log.flatMap((event, index) => {
    const text = formatLogEvent(event);

    if (text.length === 0) {
      return [];
    }

    return [
      {
        index,
        turn: event.turn,
        text,
        key: `${index}:${event.turn}:${event.type}`,
      },
    ];
  });

const groupConsecutiveTurns = (
  lines: readonly LogLineView[],
): readonly LogGroupView[] => {
  const groups: LogGroupView[] = [];

  for (const line of lines) {
    const previous = groups[groups.length - 1];

    if (previous !== undefined && previous.turn === line.turn) {
      groups[groups.length - 1] = {
        ...previous,
        lines: [...previous.lines, line],
      };
      continue;
    }

    groups.push({
      turn: line.turn,
      lines: [line],
    });
  }

  return groups;
};

