const placementHint = (
  hint: ManifestPlacementHint | null,
): PlacementHint | undefined => {
  if (hint === null) {
    return undefined;
  }

  return {
    ...(hint.roomIndex === null ? {} : { roomIndex: hint.roomIndex }),
    ...(hint.distance === null ? {} : { distance: hint.distance }),
    ...(hint.spread ? { spread: true } : {}),
  };
};

